import React, { useState, useMemo } from 'react';
import { DataConnection, BuilderPage } from '../../types';
import WindowPanel from '../WindowPanel';

interface CodeEditorProps {
  builderPages: BuilderPage[];
  activeBuilderPageId: string;
  dataConnections: DataConnection;
  onBuilderPagesChange: (pages: BuilderPage[]) => void;
}

const CodeEditor: React.FC<CodeEditorProps> = ({
  builderPages,
  activeBuilderPageId,
  dataConnections,
  onBuilderPagesChange
}) => {
  const [selectedWindow, setSelectedWindow] = useState<string | null>(null);

  // Helper functions with memoization
  const getCurrentBuilderPage = useMemo((): BuilderPage => {
    return builderPages.find(p => p.id === activeBuilderPageId) || builderPages[0];
  }, [builderPages, activeBuilderPageId]);

  const windows = useMemo(() => getCurrentBuilderPage.windows, [getCurrentBuilderPage]);

  const selectedWindowData = useMemo(() => {
    return selectedWindow ? windows.find(w => w.id === selectedWindow) : null;
  }, [windows, selectedWindow]);

  return (
    <div style={{ 
      flex: 1, 
      backgroundColor: '#f7f8fa',
      fontFamily: '"Segoe UI", "Arial", sans-serif',
      display: 'flex',
      height: '100%'
    }}>
      {/* Left Panel - Windows & Tools */}
      <div style={{
        width: '250px',
        backgroundColor: '#f8f9fa',
        borderRight: '1px solid #dee2e6',
        display: 'flex',
        flexDirection: 'column',
        padding: '16px'
      }}>
        <h3 style={{ margin: '0 0 16px 0', fontSize: '16px', fontWeight: '600', color: '#495057' }}>
          Window Editor
        </h3>
        
        {/* Window List */}
        <div style={{ marginBottom: '20px' }}>
          <h4 style={{ margin: '0 0 8px 0', fontSize: '12px', fontWeight: '600', color: '#6c757d', textTransform: 'uppercase' }}>
            Available Windows
          </h4>
          <div style={{ display: 'flex', flexDirection: 'column', gap: '6px' }}>
            {windows.map(window => (
              <div
                key={window.id}
                onClick={() => setSelectedWindow(window.id)}
                style={{
                  padding: '8px 10px',
                  backgroundColor: selectedWindow === window.id ? '#e3f2fd' : '#ffffff',
                  border: selectedWindow === window.id ? '2px solid #0066cc' : '1px solid #dee2e6',
                  borderRadius: '4px',
                  cursor: 'pointer',
                  fontSize: '11px',
                  transition: 'all 0.2s ease'
                }}
                onMouseEnter={(e) => {
                  if (selectedWindow !== window.id) {
                    e.currentTarget.style.backgroundColor = '#f8f9fa';
                    e.currentTarget.style.borderColor = '#adb5bd';
                  }
                }}
                onMouseLeave={(e) => {
                  if (selectedWindow !== window.id) {
                    e.currentTarget.style.backgroundColor = '#ffffff';
                    e.currentTarget.style.borderColor = '#dee2e6';
                  }
                }}
              >
                <div style={{ 
                  fontWeight: selectedWindow === window.id ? '600' : '500', 
                  color: selectedWindow === window.id ? '#0066cc' : '#495057', 
                  marginBottom: '2px' 
                }}>
                  {window.title}
                </div>
                <div style={{ color: '#6c757d', fontSize: '10px' }}>
                  {window.type} • {(window.editorElements || []).length} elements
                </div>
              </div>
            ))}
          </div>
        </div>

        {/* Tools */}
        <div style={{ marginBottom: '20px' }}>
          <h4 style={{ margin: '0 0 8px 0', fontSize: '12px', fontWeight: '600', color: '#6c757d', textTransform: 'uppercase' }}>
            Tools {activeTool !== 'select' && (
              <span style={{ 
                fontSize: '10px', 
                fontWeight: '500', 
                color: '#0066cc', 
                backgroundColor: '#e3f2fd', 
                padding: '2px 6px', 
                borderRadius: '3px', 
                marginLeft: '6px',
                textTransform: 'none'
              }}>
                {activeTool} active
              </span>
            )}
          </h4>
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '6px' }}>
            <div
              onClick={() => setActiveTool('select')}
              style={{
                padding: '8px 6px',
                backgroundColor: activeTool === 'select' ? '#0066cc' : '#ffffff',
                color: activeTool === 'select' ? 'white' : '#495057',
                border: activeTool === 'select' ? '2px solid #004499' : '1px solid #dee2e6',
                borderRadius: '4px',
                cursor: 'pointer',
                fontSize: '10px',
                display: 'flex',
                flexDirection: 'column',
                alignItems: 'center',
                gap: '2px',
                transition: 'all 0.2s ease'
              }}
            >
              <span style={{ fontSize: '14px' }}>↖</span>
              <span>Select</span>
            </div>
            <div
              onClick={() => setActiveTool('shape')}
              style={{
                padding: '8px 6px',
                backgroundColor: activeTool === 'shape' ? '#0066cc' : '#ffffff',
                color: activeTool === 'shape' ? 'white' : '#495057',
                border: activeTool === 'shape' ? '2px solid #004499' : '1px solid #dee2e6',
                borderRadius: '4px',
                cursor: 'pointer',
                fontSize: '10px',
                display: 'flex',
                flexDirection: 'column',
                alignItems: 'center',
                gap: '2px',
                transition: 'all 0.2s ease'
              }}
            >
              <span style={{ fontSize: '14px' }}>⬛</span>
              <span>Shape</span>
            </div>
            <div
              onClick={() => setActiveTool('text')}
              style={{
                padding: '8px 6px',
                backgroundColor: activeTool === 'text' ? '#0066cc' : '#ffffff',
                color: activeTool === 'text' ? 'white' : '#495057',
                border: activeTool === 'text' ? '2px solid #004499' : '1px solid #dee2e6',
                borderRadius: '4px',
                cursor: 'pointer',
                fontSize: '10px',
                display: 'flex',
                flexDirection: 'column',
                alignItems: 'center',
                gap: '2px',
                transition: 'all 0.2s ease'
              }}
            >
              <span style={{ fontSize: '14px' }}>A</span>
              <span>Text</span>
            </div>
            <div
              onClick={() => setActiveTool('button')}
              style={{
                padding: '8px 6px',
                backgroundColor: activeTool === 'button' ? '#0066cc' : '#ffffff',
                color: activeTool === 'button' ? 'white' : '#495057',
                border: activeTool === 'button' ? '2px solid #004499' : '1px solid #dee2e6',
                borderRadius: '4px',
                cursor: 'pointer',
                fontSize: '10px',
                display: 'flex',
                flexDirection: 'column',
                alignItems: 'center',
                gap: '2px',
                transition: 'all 0.2s ease'
              }}
            >
              <span style={{ fontSize: '14px' }}>🔘</span>
              <span>Button</span>
            </div>
          </div>
        </div>

        {/* Global Variables Preview */}
        <div style={{ marginBottom: '20px' }}>
          <h4 style={{ margin: '0 0 8px 0', fontSize: '12px', fontWeight: '600', color: '#6c757d', textTransform: 'uppercase' }}>
            Global Variables
          </h4>
          <div style={{ 
            padding: '8px', 
            backgroundColor: '#fff3cd', 
            border: '1px solid #ffeaa7', 
            borderRadius: '4px',
            fontSize: '10px',
            maxHeight: '100px',
            overflow: 'auto'
          }}>
            {Object.keys(dataConnections.globalVariables).length > 0 ? (
              Object.entries(dataConnections.globalVariables).map(([key, value]) => (
                <div key={key} style={{ marginBottom: '2px' }}>
                  <span style={{ fontWeight: '500' }}>{key}:</span> {String(value)}
                </div>
              ))
            ) : (
              <div style={{ color: '#856404' }}>No global variables defined</div>
            )}
          </div>
        </div>
      </div>

      {/* Main Content Area */}
      <div style={{ flex: 1, display: 'flex', flexDirection: 'column' }}>
        {/* Header */}
        <div style={{
          padding: '16px 20px',
          backgroundColor: '#ffffff',
          borderBottom: '1px solid #dee2e6',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'space-between'
        }}>
          <h2 style={{ margin: 0, fontSize: '18px', fontWeight: '600', color: '#495057' }}>
            Visual Element Editor
          </h2>
          <div style={{ display: 'flex', gap: '8px' }}>
            <button style={{
              padding: '6px 12px',
              backgroundColor: '#28a745',
              color: 'white',
              border: 'none',
              borderRadius: '4px',
              fontSize: '12px',
              cursor: 'pointer'
            }}>
              Preview Window
            </button>
            <button style={{
              padding: '6px 12px',
              backgroundColor: '#17a2b8',
              color: 'white',
              border: 'none',
              borderRadius: '4px',
              fontSize: '12px',
              cursor: 'pointer'
            }}>
              Export Code
            </button>
          </div>
        </div>

        {/* Split View */}
        <div style={{ flex: 1, display: 'flex' }}>
          {/* Canvas Area */}
          <div style={{ 
            flex: 1, 
            backgroundColor: '#f8f9fa',
            borderRight: '1px solid #dee2e6',
            padding: '20px',
            overflow: 'auto'
          }}>
            {selectedWindow && selectedWindowData ? (
              // Show selected window preview
              <div style={{
                backgroundColor: '#ffffff',
                border: '1px solid #dee2e6',
                borderRadius: '8px',
                minHeight: '400px',
                    position: 'relative',
                    overflow: 'hidden'
                  }}>
                    {/* Window Header */}
                    <div style={{
                      padding: '12px 16px',
                      backgroundColor: '#f8f9fa',
                      borderBottom: '1px solid #dee2e6',
                      display: 'flex',
                      alignItems: 'center',
                      justifyContent: 'space-between'
                    }}>
                      <div>
                        <h3 style={{ margin: 0, fontSize: '14px', fontWeight: '600', color: '#495057' }}>
                          {selectedWindowData.title}
                        </h3>
                        <div style={{ fontSize: '11px', color: '#6c757d', marginTop: '2px' }}>
                          {selectedWindowData.type} • Elements: {(selectedWindowData.editorElements || []).length}
                        </div>
                      </div>
                      <div style={{ fontSize: '10px', color: '#6c757d', backgroundColor: 'rgba(255,255,255,0.8)', padding: '4px 8px', borderRadius: '3px' }}>
                        {activeTool === 'select' ? 'Preview Mode' : `${activeTool.charAt(0).toUpperCase() + activeTool.slice(1)} Tool Active`}
                      </div>
                    </div>
                    
                    {/* Window Content Area */}
                    <div 
                      style={{
                        padding: '20px',
                        minHeight: '360px',
                        background: '#ffffff',
                        position: 'relative',
                        cursor: activeTool !== 'select' ? 'crosshair' : 'default'
                      }}
                      onClick={(e) => {
                        console.log('Canvas clicked!', { activeTool, selectedWindow });
                        if (activeTool !== 'select' && selectedWindow) {
                          console.log('Adding element:', activeTool);
                          const rect = e.currentTarget.getBoundingClientRect();
                          const x = e.clientX - rect.left - 20; // Subtract padding
                          const y = e.clientY - rect.top - 20; // Subtract padding
                          
                          // Ensure element doesn't go outside canvas
                          const elementWidth = activeTool === 'text' ? 120 : activeTool === 'button' ? 100 : 80;
                          const elementHeight = activeTool === 'text' ? 30 : activeTool === 'button' ? 35 : 60;
                          const maxX = Math.max(0, rect.width - elementWidth - 40); // Account for padding
                          const maxY = Math.max(0, rect.height - elementHeight - 40);
                          
                          const clampedX = Math.max(0, Math.min(x, maxX));
                          const clampedY = Math.max(0, Math.min(y, maxY));
                          
                          console.log('Position:', { x: clampedX, y: clampedY });
                          addElementToWindow(activeTool, { x: clampedX, y: clampedY });
                          setActiveTool('select'); // Switch back to select tool after placing
                        }
                      }}
                    >
                      {(selectedWindowData.editorElements || []).length === 0 ? (
                        <div style={{
                          display: 'flex',
                          alignItems: 'center',
                          justifyContent: 'center',
                          height: '300px',
                          flexDirection: 'column',
                          color: '#6c757d',
                          border: '2px dashed #dee2e6',
                          borderRadius: '6px',
                          pointerEvents: 'none' // Prevent blocking clicks
                        }}>
                          <div style={{ fontSize: '32px', marginBottom: '12px', opacity: 0.4 }}>
                            {activeTool === 'select' ? '📱' : activeTool === 'shape' ? '⬛' : activeTool === 'text' ? 'A' : '🔘'}
                          </div>
                          <h4 style={{ margin: '0 0 6px 0', fontSize: '14px', fontWeight: '500' }}>
                            {activeTool === 'select' ? 'Empty Window' : `Click to Add ${activeTool.charAt(0).toUpperCase() + activeTool.slice(1)}`}
                          </h4>
                          <p style={{ margin: '0', fontSize: '12px', textAlign: 'center', maxWidth: '250px' }}>
                            {activeTool === 'select' 
                              ? 'Use the tools on the left to add shapes, text, and buttons to this window'
                              : `Click anywhere in this area to place a ${activeTool} element`
                            }
                          </p>
                        </div>
                      ) : (
                        // Render editor elements
                        <div style={{ position: 'relative', width: '100%', height: '100%' }}>
                          {(selectedWindowData.editorElements || []).map(element => (
                            <div
                              key={element.id}
                              style={{
                                position: 'absolute',
                                left: element.position.x,
                                top: element.position.y,
                                width: element.size.width,
                                height: element.size.height,
                                border: '1px solid #dee2e6',
                                borderRadius: '3px',
                                display: 'flex',
                                alignItems: 'center',
                                justifyContent: 'center',
                                fontSize: '11px',
                                backgroundColor: element.type === 'shape' ? element.properties?.fillColor || '#e9ecef' : 
                                                 element.type === 'button' ? element.properties?.backgroundColor || '#0066cc' : 'transparent',
                                color: element.type === 'button' ? 'white' : element.properties?.fontColor || '#495057'
                              }}
                            >
                              {element.type === 'text' ? element.properties?.text || 'Text' :
                               element.type === 'button' ? element.properties?.buttonText || 'Button' :
                               element.type}
                            </div>
                          ))}
                        </div>
                      )}
                    </div>
                  </div>
            ) : (
              // Show default placeholder
              <div style={{
                backgroundColor: '#ffffff',
                border: '2px dashed #dee2e6',
                borderRadius: '8px',
                minHeight: '400px',
                padding: '20px',
                position: 'relative'
              }}>
                <div style={{
                  position: 'absolute',
                  top: '10px',
                  left: '10px',
                  fontSize: '12px',
                  color: '#6c757d',
                  backgroundColor: 'rgba(255,255,255,0.9)',
                  padding: '4px 8px',
                  borderRadius: '3px'
                }}>
                  Canvas • Select a Window
                </div>
                
                <div style={{
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  height: '100%',
                  flexDirection: 'column',
                  color: '#6c757d'
                }}>
                  <div style={{ fontSize: '48px', marginBottom: '16px', opacity: 0.3 }}>🎨</div>
                  <h3 style={{ margin: '0 0 8px 0', fontSize: '16px', fontWeight: '400' }}>
                    Visual Canvas Editor
                  </h3>
                  <p style={{ margin: '0', fontSize: '14px', textAlign: 'center', maxWidth: '300px' }}>
                    Select a window from the left panel to preview and edit it with drag & drop functionality
                  </p>
                </div>
              </div>
            )}
          </div>

          {/* Code Preview Area */}
          <div style={{ 
            flex: 1, 
            backgroundColor: '#ffffff',
            display: 'flex',
            flexDirection: 'column'
          }}>
            <div style={{
              padding: '12px 16px',
              backgroundColor: '#f8f9fa',
              borderBottom: '1px solid #dee2e6',
              fontSize: '14px',
              fontWeight: '600',
              color: '#495057'
            }}>
              Generated Code Preview
            </div>
            
            <div style={{ flex: 1, display: 'flex', flexDirection: 'column' }}>
              {/* HTML Section */}
              <div style={{ flex: 1, borderBottom: '1px solid #dee2e6' }}>
                <div style={{ 
                  padding: '8px 12px', 
                  backgroundColor: '#e3f2fd', 
                  fontSize: '11px', 
                  fontWeight: '600',
                  color: '#1565c0'
                }}>
                  HTML
                </div>
                <textarea
                  readOnly
                  value={`<div class="window-container">
  <!-- Elements will appear here when added to canvas -->
  <div class="placeholder">
    Select a window and add elements to see generated HTML
  </div>
</div>`}
                  style={{
                    width: '100%',
                    flex: 1,
                    border: 'none',
                    padding: '12px',
                    fontSize: '11px',
                    fontFamily: 'Consolas, "Courier New", monospace',
                    backgroundColor: '#fafafa',
                    color: '#495057',
                    resize: 'none'
                  }}
                />
              </div>

              {/* CSS Section */}
              <div style={{ flex: 1, borderBottom: '1px solid #dee2e6' }}>
                <div style={{ 
                  padding: '8px 12px', 
                  backgroundColor: '#e8f5e8', 
                  fontSize: '11px', 
                  fontWeight: '600',
                  color: '#2e7d32'
                }}>
                  CSS
                </div>
                <textarea
                  readOnly
                  value={`.window-container {
  font-family: Arial, sans-serif;
  position: relative;
  width: 100%;
  height: 100%;
}

/* Element styles will be generated automatically */`}
                  style={{
                    width: '100%',
                    flex: 1,
                    border: 'none',
                    padding: '12px',
                    fontSize: '11px',
                    fontFamily: 'Consolas, "Courier New", monospace',
